const fs = require("fs");
const path = require("path");

const ROOT = process.cwd();
const BACKUP_ROOT = path.join(
  ROOT,
  ".phase35u-final-backup"
);

const ASSETS = {
  "src/app/api/publications/route.ts": "",
  "src/components/publications/PublicationForm.tsx": "",
  "src/app/publications/page.tsx": "",
  "src/components/public/PublicTeachingsSection.tsx": "",
  "src/components/layout/MobileBottomNav.tsx": "",
  "src/components/public/PublicMobileBottomNav.tsx": "",
  "src/styles/production-stabilization.css": "",
  "src/components/bible/BibleReaderClient.tsx": "",
  "src/app/api/notifications/subscribe/route.ts": "",
  "src/app/api/push/subscribe/route.ts": "",
  "src/app/alerts/page.tsx": "aW1wb3J0IHsgcmVkaXJlY3QgfSBmcm9tICJuZXh0L25hdmlnYXRpb24iOwoKZXhwb3J0IGRlZmF1bHQgZnVuY3Rpb24gQWxlcnRzQWxpYXNQYWdlKCkgewogIHJlZGlyZWN0KCIvbm90aWZpY2F0aW9ucyIpOwp9Cg==",
  "src/app/church/[slug]/notifications/page.tsx": "",
  "src/app/settings/page.tsx": "",
  "public/sw.js": "",
  "src/components/public/NotificationSubscribeButton.tsx": "",
  "src/components/notifications/NotificationPermissionCard.tsx": ""
};

function decode(value) {
  return Buffer.from(
    value,
    "base64"
  ).toString("utf8");
}

function ensureDirectory(filePath) {
  fs.mkdirSync(
    path.dirname(filePath),
    { recursive: true }
  );
}

function ensureGitignoreRule(rule) {
  const gitignorePath =
    path.join(ROOT, ".gitignore");

  let content =
    fs.existsSync(gitignorePath)
      ? fs.readFileSync(
          gitignorePath,
          "utf8"
        )
      : "";

  const lines =
    content.split(/\r?\n/);

  if (!lines.includes(rule)) {
    content =
      `${content.trimEnd()}\n${rule}\n`;

    fs.writeFileSync(
      gitignorePath,
      content,
      "utf8"
    );
  }
}

fs.mkdirSync(
  BACKUP_ROOT,
  { recursive: true }
);

const manifest = [];

for (const [
  relativePath,
  encodedContent,
] of Object.entries(ASSETS)) {
  const targetPath =
    path.join(
      ROOT,
      relativePath
    );

  const backupPath =
    path.join(
      BACKUP_ROOT,
      relativePath
    );

  const existed =
    fs.existsSync(targetPath);

  if (existed) {
    ensureDirectory(
      backupPath
    );

    if (
      !fs.existsSync(
        backupPath
      )
    ) {
      fs.copyFileSync(
        targetPath,
        backupPath
      );
    }
  }

  ensureDirectory(
    targetPath
  );

  fs.writeFileSync(
    targetPath,
    decode(encodedContent),
    "utf8"
  );

  manifest.push({
    relativePath,
    existed,
  });

  console.log(
    "✅",
    relativePath
  );
}

fs.writeFileSync(
  path.join(
    BACKUP_ROOT,
    "manifest.json"
  ),
  JSON.stringify(
    manifest,
    null,
    2
  ),
  "utf8"
);

ensureGitignoreRule(
  ".phase35u-final-backup/"
);

fs.writeFileSync(
  path.join(
    ROOT,
    "PHASE35U_FINAL_INSTALL_REPORT.md"
  ),
  [
    "# Rapport d’installation Phase 35U finale",
    "",
    ...manifest.map(
      (item) =>
        `- ${item.relativePath}`
    ),
    "",
    "Sauvegardes locales : `.phase35u-final-backup/`",
    "",
    "SQL à exécuter : `phase35u_final_publications_notifications.sql`",
  ].join("\n"),
  "utf8"
);

console.log("");
console.log(
  "✅ Phase 35U finale installée."
);
console.log(
  "Exécutez maintenant le SQL Supabase, puis le contrôle."
);
